START TRANSACTION;

-- Producto ref='8435265309940' -> Marca='Idempet'
INSERT IGNORE INTO llx_categorie_product (fk_categorie, fk_product)
SELECT cat.rowid, p.rowid
FROM   llx_categorie cat
JOIN   llx_product   p ON p.ref = '8435265309940'
                      AND p.entity = 1
WHERE  cat.label    = 'Idempet'
  AND  cat.type     = 0
  AND  cat.entity   = 1
  AND  cat.fk_parent = (
           SELECT c.rowid
           FROM   llx_categorie c
           WHERE  c.label    = 'Marcas'
             AND  c.type     = 0
             AND  c.entity   = 1
             AND  c.fk_parent = 0
       );

