SELECT cat.rowid, p.rowid
FROM   llx_categorie cat
JOIN   llx_product   p ON p.ref = '413'
                      AND p.entity = 1
WHERE  cat.label    = 'Sta'
  AND  cat.type     = 0
  AND  cat.entity   = 1
  AND  cat.fk_parent = (
           SELECT c.rowid
           FROM   llx_categorie c
           WHERE  c.label    = 'Marcas'
             AND  c.type     = 0
             AND  c.entity   = 1
             AND  c.fk_parent = 0
       );

